    64→  // Orb avatar + voice
    65→  const orb = useOrbAvatar();
    66→  const stt = useDeepgramSTT();
    67→
    68→  // Queue transcripts while orb is speaking, send when quiet
    69→  const pendingTranscriptRef = useRef<string | null>(null);
    70→
    71→  // Accumulate full response text before delivering
    72→  const responseAccumulatorRef = useRef<string>("");
    73→
    74→  // Pose detection for clothing overlay
    75→  const handlePoseUpdate = useCallback((result: PoseResult) => {
    76→    setCurrentPose(result);
    77→  }, []);
    78→
    79→  usePoseDetection({
    80→    videoRef,
    81→    isVideoReady: isCameraReady,
    82→    onPoseUpdate: handlePoseUpdate,
    83→  });
    84→
    85→  // Connect socket and join user room
    86→  useEffect(() => {
    87→    socket.connect();
    88→
    89→    if (userId) {
    90→      socket.emit("join_room", { user_id: userId });
    91→    }
    92→
    93→    return () => {
    94→      socket.disconnect();
    95→    };
    96→  }, [userId]);
    97→
    98→  // Listen for session_active from backend
    99→  useEffect(() => {
   100→    const handleSessionActive = () => {
   101→      setSessionActive(true);
   102→      setIsStarting(false);
   103→      setCanvasOutfits([]);
   104→      setCanvasOutfitIndex(0);
