   111→      socket.off("session_active", handleSessionActive);
   112→    };
   113→    // eslint-disable-next-line react-hooks/exhaustive-deps
   114→  }, []);
   115→
   116→  // Listen for mira_speech events (streamed text from AI)
   117→  useEffect(() => {
   118→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   119→      // Fallback session detection
   120→      if (!sessionActive && !isStarting) {
   121→        setSessionActive(true);
   122→        setIsStarting(false);
   123→        orb.startSession();
   124→        stt.startListening();
   125→      }
   126→
   127→      if (data.is_chunk !== false) {
   128→        // Still accumulating — skip empty chunks
   129→        if (!data.text) return;
   130→        console.log("[Mirror] mira_speech chunk received");
   131→        responseAccumulatorRef.current += data.text;
   132→        orb.setOrbState("thinking");
   133→      } else {
